const messages=document.getElementById("messages"),replyForm=document.getElementById("replyForm"),responseInput=document.getElementById("response"),chatHistory=[];function createMessage(e,t){const s=document.createElement("div");s.className=`message ${e}`,s.setAttribute("data-role","ai"===e?"AI":"Human");const r=document.createElement("p");return r.textContent=t,s.appendChild(r),s}function renderMessages(){messages.innerHTML="",chatHistory.forEach(({role:e,text:t})=>{messages.appendChild(createMessage(e,t))}),messages.scrollTop=messages.scrollHeight}async function fetchPrompt(){try{const e=await fetch("getprompt");if(!e.ok)throw new Error(`HTTP ${e.status}`);const t=await e.text(),s=JSON.parse(t);chatHistory.push({role:"server",text:s.value||"Received empty prompt response."})}catch(e){chatHistory.push({role:"server",text:`Unable to fetch prompt: ${e.message}`})}finally{renderMessages()}}replyForm.addEventListener("keydown",e=>{"Enter"!==e.key||e.shiftKey||(e.preventDefault(),replyForm.dispatchEvent(new Event("submit")))}),replyForm.addEventListener("submit",async e=>{e.preventDefault();const t=responseInput.value.trim();if(t){chatHistory.push({role:"ai",text:t}),renderMessages(),responseInput.value="";try{const e=chatHistory.filter(e=>"server"!==e.role).map(({role:e,text:t})=>({role:"ai"===e?"user":"model",parts:[{text:t}]})),t=await fetch("/sendresponse",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({history:e})});if(!t.ok)throw new Error(`HTTP ${t.status}`);const s=await t.json();chatHistory.push({role:"server",text:`Rating: ${s.rating}/10\nCommentary: ${s.commentary}\nNext prompt: ${s.next_prompt}`})}catch(e){chatHistory.push({role:"server",text:`Unable to send response: ${e.message}`})}finally{renderMessages()}}}),document.addEventListener("DOMContentLoaded",()=>{fetchPrompt(),renderMessages()});